import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { environment } from 'src/environments/environment.prod';

import { BehaviorSubject, Observable } from 'rxjs';
import { SecurityDto } from 'src/app/views/auth/login/login.component';


@Injectable({
  providedIn: 'root'
})
export class SecurityPolicyService {
API_URL=environment.MEDIAN_URL;
  constructor(private httpClient: HttpClient) { }

  saveDataSecurity(obj): Observable<any> {
    console.log(obj);
    return this.httpClient.post<any>(`${this.API_URL}/securityPolicy/save`, obj)
  }
  private securityDetailsEdit = new BehaviorSubject<any>({
    authStatus: '',
authorizedBy: '',
authorizedTime: '',
createdBy: '',
createdDate: '',
isActive: '',
maxInvLogins: '',
maxPswdLength: '',
minPswdLength: '',
passwordGenerationType:'',
modifiedBy: '',
modifiedTime: '',
notifyPasswordExpiryInDays: '',
pswdComplexLcase: '',
pswdComplexNum: '',
pswdComplexSplc: '',
pswdComplexUcase: '',
pswdExpiry: '',
pswdReuseAft: '',
recordStatus: '',
version: '',
firstTimeAuth:''
  })
  setSecurityPolicy(data) {
    this.securityDetailsEdit.next(data);
  }
  getsecurityDetailsEdit() {
    return this.securityDetailsEdit.asObservable();
  }
  fetchSecurityPolicyService() {
    return this.httpClient.get<SecurityDto>(`${this.API_URL}/securityPolicy/fetch`);
  }
 
  getSecurityPolicyForAuth() {
    return this.httpClient.get<any[]>(`${this.API_URL}/authorization/getSecurityPolicy`);
  }
  getMonitorData() {
    return this.httpClient.get<any>(`${this.API_URL}/excelDataForProcessScreeen/getMonitorData`);
  }
  // fetchSecurityPolicyService() {
  //   return this.httpClient.get<any>(`${API_URL}/securityPolicy/fetch`);
  // }
    changePassword(passwordDTO: object) {
    return this.httpClient.post<boolean>(`${this.API_URL}/user/changePassword`, passwordDTO);
  }
  authSecurity(operation,obj){
    return this.httpClient.put(`${this.API_URL}/securityPolicy/${operation}`,obj)
  }
 getAllSecurityPolicy(pageNo,pageSize,sortBy){
    return this.httpClient.get<any>(`${this.API_URL}/securityPolicy/getSecurityPolicies?pageNo=${0}&pageSize=${1000}&sortBy=${sortBy}`)
  }
  //   fetchSecurityPolicyService() {
  //   return this.httpClient.get<any>(`${this.API_URL}/securityPolicy/fetch`);
  // }
}
